const content=document.querySelector('#content');let editing=null;
function save(){localStorage.setItem(KEY,JSON.stringify(records))}function esc(s=''){return String(s).replace(/[&<>'"]/g,x=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[x]))}
function setView(view){document.querySelectorAll('nav button').forEach(b=>b.classList.toggle('active',b.dataset.view===view));document.querySelector('#crumb').textContent='Inicio / '+({dashboard:'Dashboard',collaborators:'Colaboradores',reports:'Reportes'}[view]||'Estudio');document.querySelector('#title').textContent=({dashboard:'Resumen ejecutivo',collaborators:'Gestión de colaboradores',reports:'Reportes y exportación',form:'Estudio socioeconómico'}[view]);if(view==='dashboard')dashboard();if(view==='collaborators')collaborators();if(view==='reports')reports();if(view==='form')form(editing)}
function dashboard(){let total=records.length,done=records.filter(r=>r.status==='Completada').length,avg=total?Math.round(records.reduce((a,r)=>a+Number(r.age),0)/total):0,credits=records.filter(r=>r.credits?.length).length,need=records.filter(r=>['Difícil','Muy difícil'].includes(r.economy)).length,depts={};records.forEach(r=>depts[r.department]=(depts[r.department]||0)+1);content.innerHTML=`<div class="actions"><p class="muted">Información para mejorar el bienestar del equipo.</p><button class="primary" onclick="newRecord()">+ Nuevo estudio</button></div><div class="cards">${[['♙',total,'Colaboradores registrados'],['✓',done,'Encuestas completadas'],['◷',avg+' años','Promedio de edad'],['▣',credits,'Personas con créditos'],['⌁',need,'Requieren apoyo financiero']].map(x=>`<div class="card"><i>${x[0]}</i><b>${x[1]}</b><span>${x[2]}</span></div>`).join('')}</div><div class="two"><div class="card"><h2>Colaboradores por departamento</h2>${Object.entries(depts).map(([n,v])=>`<div class="bar"><span>${esc(n)}</span><div><i style="width:${v/total*100}%"></i></div><b>${v}</b></div>`).join('')||'<p class="empty">Sin datos</p>'}</div><div class="card"><h2>Estudios recientes</h2>${records.slice(0,5).map(r=>`<p><b>${esc(r.name)}</b><br><small class="muted">${esc(r.department)} · ${esc(r.position)}</small></p>`).join('')}</div></div>`}
function collaborators(){content.innerHTML=`<div class="actions"><form class="search" onsubmit="event.preventDefault();findRecords(this.q.value)"><input name="q" placeholder="Buscar nombre, puesto o departamento"><button class="btn">Buscar</button></form><button class="primary" onclick="newRecord()">+ Nuevo colaborador</button></div><div class="card table">${table(records)}</div>`}
function table(rows){return `<table><thead><tr><th>Colaborador</th><th>Departamento</th><th>Puesto</th><th>Fecha</th><th>Estado</th><th>Acciones</th></tr></thead><tbody>${rows.map(r=>`<tr><td><b>${esc(r.name)}</b></td><td>${esc(r.department)}</td><td>${esc(r.position)}</td><td>${esc(r.date)}</td><td><span class="badge ${r.status==='Completada'?'done':'draft'}">${r.status}</span></td><td><button class="row-button" onclick="editRecord(${r.id})">Editar</button> <button class="row-button delete" onclick="removeRecord(${r.id})">Eliminar</button></td></tr>`).join('')}</tbody></table>${rows.length?'':'<p class="empty">No hay resultados.</p>'}`}
function findRecords(q){let x=q.toLowerCase();document.querySelector('.table').innerHTML=table(records.filter(r=>(r.name+r.department+r.position).toLowerCase().includes(x)))}
function newRecord(){editing=null;setView('form')}function editRecord(id){editing=records.find(r=>r.id===id);setView('form')}function removeRecord(id){if(confirm('¿Eliminar este registro?')){records=records.filter(r=>r.id!==id);save();collaborators()}}
function checked(group,items,old=[]){return `<div><h3>${group}</h3>${items.map(x=>`<label><input type="checkbox" name="${group}" value="${x}" ${old.includes(x)?'checked':''}>${x}</label>`).join('')}</div>`}
function form(r){r=r||{id:'',name:'',sex:'',age:'',department:'',position:'',housing:'',economy:'',debt:'',credits:[],training:[],date:new Date().toISOString().slice(0,10)};content.innerHTML=`<form class="form" onsubmit="storeRecord(event,${r.id||0})"><div class="card"><h2>Datos generales</h2><div class="form-grid"><label>Nombre completo*<input name="name" required value="${esc(r.name)}"></label><label>Sexo*<select name="sex" required><option>${esc(r.sex)}</option><option>Mujer</option><option>Hombre</option></select></label><label>Edad*<input name="age" type="number" min="18" required value="${esc(r.age)}"></label><label>Departamento*<input name="department" required value="${esc(r.department)}"></label><label>Puesto*<input name="position" required value="${esc(r.position)}"></label><label>Tipo de vivienda<input name="housing" value="${esc(r.housing)}" placeholder="Propia, Rentada, Infonavit"></label><label>Economía<select name="economy"><option>${esc(r.economy)}</option><option>Excelente</option><option>Buena</option><option>Regular</option><option>Difícil</option><option>Muy difícil</option></select></label><label>Deuda<select name="debt"><option>${esc(r.debt)}</option><option>Sin deuda</option><option>0-20%</option><option>21-40%</option><option>41-60%</option><option>Más de 60%</option></select></label></div></div><div class="card"><h2>Créditos y desarrollo</h2><div class="checks">${checked('credits',['Tarjetas de crédito','Automotriz','Hipotecario','Infonavit','Crédito personal'],r.credits)}${checked('training',['Ventas','Liderazgo','Power BI','Excel','Finanzas','Tecnología'],r.training)}<div><h3>Comentarios</h3><textarea name="comments" rows="7" placeholder="Observaciones relevantes"></textarea></div></div></div><div class="form-actions"><button type="button" class="btn" onclick="setView('collaborators')">Cancelar</button><button name="status" value="Borrador" class="btn">Guardar borrador</button><button name="status" value="Completada" class="primary">Finalizar estudio</button></div></form>`}
function storeRecord(e,id){e.preventDefault();let f=new FormData(e.target),status=e.submitter.value,obj={id:id||Date.now(),name:f.get('name'),sex:f.get('sex'),age:Number(f.get('age')),department:f.get('department'),position:f.get('position'),housing:f.get('housing'),economy:f.get('economy'),debt:f.get('debt'),credits:f.getAll('credits'),training:f.getAll('training'),status,date:new Date().toISOString().slice(0,10)};if(id)records=records.map(r=>r.id===id?obj:r);else records.unshift(obj);save();setView('collaborators')}
function reports(){content.innerHTML=`<div class="actions"><p class="muted">Exporta los registros para analizarlos en Excel.</p><button class="primary" onclick="downloadCSV()">⇩ Exportar CSV</button></div><div class="two"><div class="card"><h2>Registros</h2><p style="font-size:34px;font-weight:bold">${records.length}</p><p class="muted">Estudios registrados</p></div><div class="card"><h2>Uso sin servidor</h2><p class="muted">Los datos se conservan en este navegador. Para datos compartidos entre usuarios utiliza la versión PHP + MySQL.</p></div></div>`}
function downloadCSV(){let rows=[['Nombre','Sexo','Edad','Departamento','Puesto','Vivienda','Economía','Deuda','Estado','Fecha'],...records.map(r=>[r.name,r.sex,r.age,r.department,r.position,r.housing,r.economy,r.debt,r.status,r.date])],csv=rows.map(r=>r.map(x=>`"${String(x).replaceAll('"','""')}"`).join(',')).join('\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='reporte-bienestar.csv';a.click()}
const loginScreen=document.querySelector('#login'),appScreen=document.querySelector('#app');
document.querySelector('#login-form').onsubmit=e=>{e.preventDefault();if(document.querySelector('#email').value==='admin@empresa.com'&&document.querySelector('#password').value==='admin123'){loginScreen.hidden=true;appScreen.hidden=false;dashboard()}else alert('Credenciales incorrectas')};document.querySelectorAll('nav button').forEach(b=>b.onclick=()=>setView(b.dataset.view));document.querySelector('#logout').onclick=()=>{appScreen.hidden=true;loginScreen.hidden=false};

