function dashboard(){const source=records.map(r=>({...r,index:socioeconomicIndex(r)})),departments=[...new Set(source.map(r=>r.department||'Sin departamento'))].sort(),rows=source.filter(r=>(!executiveFilters.department||r.department===executiveFilters.department)&&(!executiveFilters.status||r.status===executiveFilters.status)&&(!executiveFilters.risk||risk(r.index)===executiveFilters.risk)),total=rows.length,completed=rows.filter(r=>r.status==='Completada').length,average=total?Math.round(rows.reduce((sum,r)=>sum+r.index,0)/total):0,critical=rows.filter(r=>r.index<60).length,watch=rows.filter(r=>r.index>=60&&r.index<75).length,stable=rows.filter(r=>r.index>=75).length,financial=rows.filter(r=>norm(response(r,'considera su economia',r.economy)).includes('dificil')).length,byDepartment={};rows.forEach(r=>byDepartment[r.department||'Sin departamento']=(byDepartment[r.department||'Sin departamento']||0)+1);const grouped=Object.entries(byDepartment).sort((a,b)=>b[1]-a[1]),max=Math.max(...grouped.map(x=>x[1]),1),ranking=[...rows].sort((a,b)=>a.index-b.index).slice(0,8),lead=grouped[0],alerts=[];if(critical)alerts.push(`${critical} persona${critical===1?'':'s'} con vulnerabilidad crítica requiere${critical===1?'':'n'} atención prioritaria.`);if(financial)alerts.push(`${financial} registro${financial===1?'':'s'} reporta${financial===1?'':'n'} economía difícil o muy difícil.`);if(!alerts.length&&total)alerts.push('No se identifican alertas críticas bajo los filtros actuales.');const bar=grouped.map(([label,value])=>`<div class="exec-bar"><span>${esc(label)}</span><div><i style="width:${Math.round(value/max*100)}%"></i></div><b>${value}</b></div>`).join('')||'<p class="empty">Sin información suficiente.</p>';content.innerHTML=`<section class="exec-hero"><div><p class="eyebrow">DIRECCIÓN GENERAL · RECURSOS HUMANOS</p><h2>Dashboard Ejecutivo Socioeconómico</h2><p>Indicadores estratégicos para priorizar decisiones y acciones de bienestar.</p></div><div class="exec-index"><small>Índice Socioeconómico</small><strong>${average}<em>/100</em></strong><span class="traffic ${riskColor(average)}">${risk(average)}</span></div></section><section class="exec-filters card"><div><label>Departamento<select id="executive-department" onchange="filterExecutiveDashboard()"><option value="">Todos los departamentos</option>${departments.map(d=>`<option value="${esc(d)}" ${executiveFilters.department===d?'selected':''}>${esc(d)}</option>`).join('')}</select></label><label>Estado<select id="executive-status" onchange="filterExecutiveDashboard()"><option value="">Todos los estados</option><option ${executiveFilters.status==='Completada'?'selected':''}>Completada</option><option ${executiveFilters.status==='Borrador'?'selected':''}>Borrador</option></select></label><label>Semáforo<select id="executive-risk" onchange="filterExecutiveDashboard()"><option value="">Todos los niveles</option>${['Crítico','En seguimiento','Estable'].map(x=>`<option ${executiveFilters.risk===x?'selected':''}>${x}</option>`).join('')}</select></label></div><button class="btn" onclick="resetExecutiveFilters()">Limpiar filtros</button></section><section class="exec-kpis"><article class="card exec-kpi"><span>Estudios analizados</span><b>${total}</b><small>${completed} completados · ${total?Math.round(completed/total*100):0}% de avance</small></article><article class="card exec-kpi"><span>Vulnerabilidad crítica</span><b class="text-red">${critical}</b><small>Índice menor a 60 puntos</small></article><article class="card exec-kpi"><span>En seguimiento</span><b class="text-amber">${watch}</b><small>Índice entre 60 y 74</small></article><article class="card exec-kpi"><span>Situación estable</span><b class="text-green">${stable}</b><small>Índice igual o superior a 75</small></article></section><section class="exec-grid"><article class="card"><div class="card-heading"><div><p class="eyebrow">DISTRIBUCIÓN</p><h2>Registros por departamento</h2></div><span class="muted">${total} total</span></div>${bar}</article><article class="card"><div class="card-heading"><div><p class="eyebrow">SEMÁFORO DE RIESGO</p><h2>Mapa de vulnerabilidad</h2></div></div><div class="risk-donut"><div><b>${total?Math.round(stable/total*100):0}%</b><span>estable</span></div></div><div class="risk-legend"><span><i class="dot green"></i>Estable <b>${stable}</b></span><span><i class="dot amber"></i>Seguimiento <b>${watch}</b></span><span><i class="dot red"></i>Crítico <b>${critical}</b></span></div></article></section><section class="exec-grid"><article class="card"><div class="card-heading"><div><p class="eyebrow">RANKING DE ATENCIÓN</p><h2>Casos con menor índice</h2></div><span class="traffic red">Priorizar</span></div><div class="table"><table class="exec-table"><thead><tr><th>Colaborador</th><th>Departamento</th><th>Índice</th><th>Semáforo</th></tr></thead><tbody>${ranking.map(r=>`<tr><td><b>${esc(r.name||'Sin nombre')}</b></td><td>${esc(r.department||'Sin departamento')}</td><td><strong>${r.index}</strong></td><td><span class="traffic ${riskColor(r.index)}">${risk(r.index)}</span></td></tr>`).join('')}</tbody></table>${ranking.length?'':'<p class="empty">No hay registros bajo los filtros seleccionados.</p>'}</div></article><article class="card"><div class="card-heading"><div><p class="eyebrow">ALERTAS AUTOMÁTICAS</p><h2>Señales para intervención</h2></div></div><div class="alerts">${alerts.map((item,index)=>`<div class="alert ${critical&&index===0?'danger':'notice'}"><i>${critical&&index===0?'!':'i'}</i><span>${esc(item)}</span></div>`).join('')}</div><div class="recommendations"><b>Recomendación prioritaria</b><p>${critical?'Canalizar los casos críticos a una entrevista confidencial de RH y definir apoyos según el factor de riesgo identificado.':'Mantener monitoreo trimestral y fortalecer acciones preventivas de educación financiera y beneficios.'}</p></div></article></section><section class="card exec-summary"><div class="card-heading"><div><p class="eyebrow">RESUMEN EJECUTIVO AUTOMÁTICO</p><h2>Hallazgos y recomendaciones</h2></div><span class="muted">Actualizado con los filtros actuales</span></div><p>${esc(total?`Se analizaron ${total} estudio${total===1?'':'s'}; el Índice Socioeconómico promedio es ${average}/100. ${critical?`${critical} caso${critical===1?'':'s'} requiere${critical===1?'':'n'} atención prioritaria.`:'La población analizada se mantiene mayormente estable.'} ${lead?`${lead[0]} concentra la mayor participación con ${lead[1]} registro${lead[1]===1?'':'s'}.`:''}`:'No hay registros que coincidan con los filtros seleccionados.')}</p><div class="summary-columns"><div><b>Tendencia</b><p>${total?Math.round(completed/total*100):0}% de avance de captura y ${stable} colaborador${stable===1?'':'es'} en situación estable.</p></div><div><b>Riesgo detectado</b><p>${critical?`${critical} caso${critical===1?'':'s'} crítico${critical===1?'':'s'} y ${watch} en seguimiento.`:'No hay casos críticos en la selección actual.'}</p></div><div><b>Acción sugerida</b><p>Revisar el ranking, validar factores individuales y medir el resultado de las acciones en el siguiente corte.</p></div></div></section>`}
